<?php
/** Sustainable Catalyst Lab v0.30.0 Reproducible Experiment Framework. */
if (!defined('ABSPATH')) { exit; }
final class SC_Lab_Experiment_Framework_V0300 {
    const VERSION='0.30.0'; private static $initialized=false;
    public static function init(){if(self::$initialized){return;}self::$initialized=true;add_action('rest_api_init',array(__CLASS__,'routes'));add_filter('sc_lab_module_aliases_v02631',array(__CLASS__,'aliases'));}
    public static function aliases($aliases){$aliases=is_array($aliases)?$aliases:array();foreach(array('experiment-framework','reproducible-experiments','experiment-protocols','experiment-design') as $a){$aliases[$a]='experiment-framework';}return $aliases;}
    public static function routes(){register_rest_route('sc-lab/v1','/experiments/v0300/health',array('methods'=>WP_REST_Server::READABLE,'callback'=>array(__CLASS__,'health'),'permission_callback'=>'__return_true'));register_rest_route('sc-lab/v1','/experiments/v0300/schema',array('methods'=>WP_REST_Server::READABLE,'callback'=>array(__CLASS__,'schema'),'permission_callback'=>'__return_true'));}
    private static function file_state($rel){$p=SC_LAB_DIR.$rel;return array('exists'=>is_file($p),'sha256'=>is_file($p)?hash_file('sha256',$p):null);}
    public static function schema(){return rest_ensure_response(array('ok'=>true,'version'=>self::VERSION,'protocolSchema'=>'sc-lab-experiment-protocol/0.30.0','runSchema'=>'sc-lab-experiment-run/0.30.0','comparisonSchema'=>'sc-lab-experiment-comparison/0.30.0','reportSchema'=>'sc-lab-experiment-report/0.30.0','bundleSchema'=>'sc-lab-experiment-bundle/0.30.0','storage'=>'browser-local-project-records','pythonVerification'=>true,'serverBackedRegistry'=>false));}
    public static function health(){$required=array('assets/js/modules/experiment-framework-v0300.js','assets/css/sc-lab-experiment-framework-v0300.css','contracts/experiment-protocol-v0300.schema.json','contracts/experiment-run-v0300.schema.json','contracts/experiment-report-v0300.schema.json','contracts/experiment-framework-policy-v0300.json','includes/class-sc-lab-experiment-framework-v0300.php');$files=array();foreach($required as $rel){$files[$rel]=self::file_state($rel);} $ok=!in_array(false,array_map(function($r){return !empty($r['exists']);},$files),true);return rest_ensure_response(array('ok'=>$ok,'status'=>$ok?'ready':'incomplete','version'=>self::VERSION,'release'=>defined('SC_LAB_VERSION')?SC_LAB_VERSION:null,'architecture'=>'project-scoped-reproducible-experiment-registry','serverBackedRegistry'=>false,'files'=>$files,'time'=>gmdate('c')));}
}
